Here's a modern MSTest test class covering async testing, timeouts, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    [TestCategory("Unit")]
    [Timeout(5000)] // fail-safe: prevents hung tests
    public async Task FetchAsync_ValidUrl_ReturnsContent()
    {
        var handler = new MockHttpMessageHandler("expected content", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("expected content", result);
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange: a handler that delays long enough to be cancelled
        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();

        // Act: cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_CancellationDuringRequest_ThrowsOperationCanceled()
    {
        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable mock handler — no external mocking library needed
    private sealed class MockHttpMessageHandler : HttpMessageHandler
    {
        private readonly string _content;
        private readonly HttpStatusCode _statusCode;
        private readonly TimeSpan _delay;

        public MockHttpMessageHandler(string content, HttpStatusCode statusCode,
            TimeSpan delay = default)
        {
            _content = content;
            _statusCode = statusCode;
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
                await Task.Delay(_delay, cancellationToken);

            return new HttpResponseMessage(_statusCode)
            {
                Content = new StringContent(_content)
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `async Task` return type | MSTest natively awaits async tests — never use `async void` |
| `[Timeout(5000)]` | Prevents tests from hanging indefinitely if the await never completes |
| `Assert.ThrowsExactlyAsync` | Modern MSTest v3+ assertion for async exception testing (prefers exact type over `ThrowsException`) |
| `CancellationTokenSource` with timeout | Tests that cancellation mid-flight works correctly |
| Custom `HttpMessageHandler` | The seam `HttpClient` provides — no mocking framework needed |

**Avoid these common pitfalls:**
- **`.Result` / `.Wait()`** — deadlocks; always `await`
- **`[Timeout]` on `async void`** — MSTest can't track the task; use `async Task`
- **`Assert.ThrowsExceptionAsync`** — catches derived types silently; `ThrowsExactlyAsync` (MSTest 3.4+) is stricter
